function lonelyNumbers(nums) {
    const count = {};
    const result = [];

    for (const num of nums) {
        if (count[num] === undefined) {
            count[num] = 1;
        } else {
            count[num]++;
        }
    }

    for (const key in count) {
        const k = parseInt(key);
        if (count[k] === 1 && count[k - 1] === undefined && count[k + 1] === undefined) {
            result.push(k);
        }
    }

    return result;
}
